import{_ as a,a as t,b as o,c as i,d,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as l,o as n,c as p,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Aggiungere un canale Dropbox","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/dropbox.md","filePath":"it-IT/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"it-IT/upload/dropbox.md"};function g(h,e,u,b,m,f){return n(),p("div",null,[...e[0]||(e[0]=[s('<h1 id="aggiungere-un-canale-dropbox" tabindex="-1">Aggiungere un canale Dropbox <a class="header-anchor" href="#aggiungere-un-canale-dropbox" aria-label="Permalink to &quot;Aggiungere un canale Dropbox&quot;">​</a></h1><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>A cosa serve</th></tr></thead><tbody><tr><td>Account Dropbox</td><td>Per accedere e autorizzare l&#39;app</td></tr><tr><td>App Dropbox</td><td>Per generare <code>App Key</code> e <code>App Secret</code></td></tr><tr><td>Dominio ImgBed</td><td>Per l&#39;URI di redirect OAuth</td></tr><tr><td>Spazio Dropbox disponibile</td><td>Archivio effettivo dei file</td></tr></tbody></table><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h2><h3 id="passaggio-1-crea-un-app-dropbox" tabindex="-1">Passaggio 1: crea un&#39;app Dropbox <a class="header-anchor" href="#passaggio-1-crea-un-app-dropbox" aria-label="Permalink to &quot;Passaggio 1: crea un&#39;app Dropbox&quot;">​</a></h3><ol><li>Apri Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Crea una nuova app.</li><li>Come tipo di accesso scegli:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Dai all&#39;app un nome riconoscibile, per esempio <code>imgbed-app</code>.</li><li>Dopo la creazione apri la pagina dettagli dell&#39;app.</li></ol><p>Tipo di accesso consigliato:</p><table tabindex="0"><thead><tr><th>Tipo di accesso</th><th>Consiglio</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Consigliato. È coerente con il modo in cui ImgBed archivia i file.</td></tr><tr><td><code>Full Dropbox</code></td><td>Non consigliato. ImgBed non ha bisogno di accesso completo all&#39;account.</td></tr></tbody></table><p><img src="'+a+'" alt="Crea app Dropbox" loading="lazy"></p><h3 id="passaggio-2-aggiungi-la-redirect-uri" tabindex="-1">Passaggio 2: aggiungi la Redirect URI <a class="header-anchor" href="#passaggio-2-aggiungi-la-redirect-uri" aria-label="Permalink to &quot;Passaggio 2: aggiungi la Redirect URI&quot;">​</a></h3><p>Nella pagina dettagli dell&#39;app Dropbox trova le impostazioni OAuth o Redirect URI e aggiungi:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Se usi il pannello admin da più domini, aggiungi ogni URL di callback corrispondente.</p><p><img src="'+t+'" alt="Configura Redirect URI" loading="lazy"></p><h3 id="passaggio-3-configura-i-permessi-dell-app" tabindex="-1">Passaggio 3: configura i permessi dell&#39;app <a class="header-anchor" href="#passaggio-3-configura-i-permessi-dell-app" aria-label="Permalink to &quot;Passaggio 3: configura i permessi dell&#39;app&quot;">​</a></h3><p>Apri la scheda <code>Permissions</code> e abilita almeno questi scope:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Obbligatorio</th><th>Scopo</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Sì</td><td>Legge informazioni account e quota</td></tr><tr><td><code>files.metadata.read</code></td><td>Sì</td><td>Legge metadati di file e cartelle per i controlli di percorso</td></tr><tr><td><code>files.metadata.write</code></td><td>Sì</td><td>Crea cartelle e scrive metadati</td></tr><tr><td><code>files.content.write</code></td><td>Sì</td><td>Carica file. Senza questo scope compare <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Consigliato</td><td>Permette download, anteprima e link temporanei</td></tr></tbody></table><p>Dopo aver selezionato gli scope, clicca su <code>Submit</code> in fondo alla pagina.</p><p><img src="'+o+'" alt="Aggiungi permessi" loading="lazy"></p><p>Importante:</p><table tabindex="0"><thead><tr><th>Situazione</th><th>Cosa fare</th></tr></thead><tbody><tr><td>Hai modificato gli scope</td><td>Esegui di nuovo l&#39;autorizzazione e ottieni un nuovo <code>Refresh Token</code>.</td></tr><tr><td>Non hai riautorizzato</td><td>Il vecchio token non acquisisce i nuovi permessi; gli upload possono continuare a fallire.</td></tr></tbody></table><h3 id="passaggio-4-copia-le-credenziali-dell-app" tabindex="-1">Passaggio 4: copia le credenziali dell&#39;app <a class="header-anchor" href="#passaggio-4-copia-le-credenziali-dell-app" aria-label="Permalink to &quot;Passaggio 4: copia le credenziali dell&#39;app&quot;">​</a></h3><p>Salva questi due valori dalla pagina dell&#39;app Dropbox:</p><table tabindex="0"><thead><tr><th>Campo Dropbox</th><th>Campo ImgBed</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="passaggio-5-compila-il-canale-dropbox" tabindex="-1">Passaggio 5: compila il canale Dropbox <a class="header-anchor" href="#passaggio-5-compila-il-canale-dropbox" aria-label="Permalink to &quot;Passaggio 5: compila il canale Dropbox&quot;">​</a></h3><p>In Impostazioni di caricamento scegli <code>Dropbox</code> e compila:</p><table tabindex="0"><thead><tr><th>Campo ImgBed</th><th>Cosa inserire</th></tr></thead><tbody><tr><td>Nome canale</td><td>Un nome riconoscibile, per esempio <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td><code>App key</code> di Dropbox</td></tr><tr><td>App Secret</td><td><code>App secret</code> di Dropbox</td></tr><tr><td>Refresh Token</td><td>Lascialo vuoto per ora</td></tr><tr><td>Directory radice</td><td>Opzionale. Default <code>imgbed</code>.</td></tr><tr><td>Nota</td><td>Opzionale</td></tr></tbody></table><p><img src="'+i+'" alt="Ottieni token" loading="lazy"></p><h3 id="passaggio-6-ottieni-il-refresh-token" tabindex="-1">Passaggio 6: ottieni il Refresh Token <a class="header-anchor" href="#passaggio-6-ottieni-il-refresh-token" aria-label="Permalink to &quot;Passaggio 6: ottieni il Refresh Token&quot;">​</a></h3><ol><li>In ImgBed clicca su <code>Get Token</code>.</li><li>Accedi con l&#39;account Dropbox da collegare.</li><li>Approva la richiesta di autorizzazione.</li><li>La pagina di callback mostrerà un <code>Refresh Token</code>.</li><li>Copialo.</li><li>Torna in ImgBed e incollalo nel campo <code>Refresh Token</code>.</li></ol><p><img src="'+d+'" alt="Copia token" loading="lazy"></p><h2 id="verifica" tabindex="-1">Verifica <a class="header-anchor" href="#verifica" aria-label="Permalink to &quot;Verifica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controllo</th><th>Risultato atteso</th></tr></thead><tbody><tr><td>Scheda canale</td><td>Il canale Dropbox compare dopo il salvataggio.</td></tr><tr><td>Interruttore canale</td><td>Il canale può essere abilitato.</td></tr><tr><td>Token salvato</td><td>La pagina dettaglio mostra che il <code>Refresh Token</code> è stato salvato.</td></tr><tr><td>Upload di prova</td><td>Un&#39;immagine di prova compare nella cartella dell&#39;app Dropbox.</td></tr></tbody></table><p>Se i limiti quota sono attivi, esegui la query quota. Dopo una query riuscita, la scheda mostra spazio usato, spazio totale e ultimo aggiornamento.</p><p><img src="'+r+`" alt="Query quota riuscita" loading="lazy"></p><h2 id="risoluzione-problemi" tabindex="-1">Risoluzione problemi <a class="header-anchor" href="#risoluzione-problemi" aria-label="Permalink to &quot;Risoluzione problemi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problema</th><th>Soluzione</th></tr></thead><tbody><tr><td>ImgBed segnala configurazione incompleta</td><td>Verifica che <code>App Key</code>, <code>App Secret</code> e <code>Refresh Token</code> siano compilati.</td></tr><tr><td>L&#39;autorizzazione riesce ma non compare il <code>Refresh Token</code></td><td>Clicca di nuovo <code>Get Token</code> e assicurati che venga usato il flusso offline.</td></tr><tr><td>Upload fallisce con <code>required scope &#39;files.content.write&#39;</code></td><td>Abilita <code>files.content.write</code>, clicca <code>Submit</code>, poi ottieni un nuovo <code>Refresh Token</code>.</td></tr><tr><td>Callback fallisce</td><td>Conferma che la redirect URI sia <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>File non trovati</td><td>Verifica che l&#39;app Dropbox sia stata creata in modalità <code>App folder</code>.</td></tr></tbody></table><h2 id="flusso-rapido" tabindex="-1">Flusso rapido <a class="header-anchor" href="#flusso-rapido" aria-label="Permalink to &quot;Flusso rapido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Apri Dropbox App Console</span></span>
<span class="line"><span>-&gt; Crea un&#39;app</span></span>
<span class="line"><span>-&gt; Scegli accesso App folder</span></span>
<span class="line"><span>-&gt; Aggiungi https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Abilita account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; Opzionalmente abilita files.content.read</span></span>
<span class="line"><span>-&gt; Clicca Submit</span></span>
<span class="line"><span>-&gt; Copia App Key e App Secret</span></span>
<span class="line"><span>-&gt; Inseriscili in ImgBed</span></span>
<span class="line"><span>-&gt; Clicca Get Token</span></span>
<span class="line"><span>-&gt; Copia il Refresh Token dalla pagina di callback</span></span>
<span class="line"><span>-&gt; Incollalo in ImgBed e salva</span></span></code></pre></div><h2 id="riferimenti" tabindex="-1">Riferimenti <a class="header-anchor" href="#riferimenti" aria-label="Permalink to &quot;Riferimenti&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const z=l(c,[["render",g]]);export{k as __pageData,z as default};
